-- urun_id whitelist dışı sipariş kalemlerini sil (demo ürünlere bağlı olanlar)
DELETE FROM `siparis_kalemleri` WHERE `urun_id` NOT IN (SELECT `id` FROM `urunler`);

-- Demo taslak kalemsiz siparişleri sil (canlı verinin numarasıyla çakışanlar kayıp oluyor, temiz başlangıç)
DELETE FROM `satis_siparisleri`
  WHERE `durum` = 'taslak'
    AND `id` NOT IN (SELECT DISTINCT `siparis_id` FROM `siparis_kalemleri`);

-- Üretim emirleri bu seed'de yok; kalem+sipariş durumlarını yeni mimari için resetle
UPDATE `siparis_kalemleri` SET `uretim_durumu` = 'beklemede';
UPDATE `satis_siparisleri` SET `durum` = 'onaylandi' WHERE `durum` IN ('uretimde','kismen_sevk','tamamlandi','kapali');

SET FOREIGN_KEY_CHECKS = 1;
